#include<bits/stdc++.h>
using namespace std;
int n,m,val[100010],f[100010][2][2];
int dfncnt,dfn[100010];
vector<int> mp[100010];
int dfs(int x,int fa)
{
    dfn[x]=++dfncnt;
    f[x][1][0]=f[x][1][1]=val[x];
    int rt=0;
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            if(!dfn[i])
            {
                int root=dfs(i,x);
                if(dfn[x]!=root)
                {
                    rt=root;
                }
                f[x][1][0]+=f[i][0][0];
                f[x][1][1]+=f[i][0][(int)(dfn[x]!=root)];
                if(dfn[x]==root)
                {
                    f[x][0][0]+=max({f[i][0][0],f[i][0][1],f[i][1][0],f[i][1][1]});
                    f[x][0][1]+=max({f[i][0][0],f[i][0][1],f[i][1][0],f[i][1][1]});
                }
                else
                {
                    f[x][0][0]+=max(f[i][0][0],f[i][1][0]);
                    f[x][0][1]+=max(f[i][0][1],f[i][1][1]);
                }
            }
            else if(dfn[x]>dfn[i])
            {
                rt=dfn[i];
                f[x][1][0]=f[x][0][1]=-1e9;
            }
        }
    }
    return rt;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    dfs(1,0);
    printf("%d",max({f[1][0][0],f[1][0][1],f[1][1][0],f[1][1][1]}));
    return 0;
}
